// Parse Groq output — strip markdown if added
const raw = $input.first().json.output || '';
const cleaned = raw.replace(/```json/gi, '').replace(/```/g, '').trim();
try {
  const parsed = JSON.parse(cleaned);
  return [{ json: parsed }];
} catch(e) {
  return [{ json: { parse_error: true, raw_output: raw } }];
}

const freight = $input.first().json;

const quoteId = 'FQ-' + Date.now();
const intakeTime = new Date().toISOString();
const bidDeadline = new Date(Date.now() + 2 * 60 * 60 * 1000).toISOString();

const carrierRules = {
  default: ['Amazon Freight','UPS Freight','FedEx Freight','XPO Logistics','Old Dominion','Estes Express']
};
const markupRules = { default: 0.15 };

const customerEmail = freight.customer_email || '';
const carriers = carrierRules[customerEmail] || carrierRules.default;
const markupPct = markupRules[customerEmail] ?? markupRules.default;

return [{
  json: {
    quote_id: quoteId,
    status: 'INTAKE',
    intake_time: intakeTime,
    bid_deadline: bidDeadline,
    customer_email: customerEmail,
    customer_name: freight.customer_name,
    origin: freight.origin,
    destination: freight.destination,
    weight_lbs: freight.weight_lbs,
    dimensions: freight.dimensions,
    freight_class: freight.freight_class,
    hazmat: freight.hazmat || false,
    accessorials: JSON.stringify(freight.accessorials || []),
    pickup_date: freight.required_pickup_date,
    special_notes: freight.special_notes,
    eligible_carriers: JSON.stringify(carriers),
    markup_pct: markupPct,
    carriers_contacted: carriers.length
  }
}];

const record = $input.first().json;
const carriers = JSON.parse(record.eligible_carriers);

const rfqBody = `Hello,

We have a freight shipment requiring immediate pricing. Please respond within 2 hours.

Quote Reference: ${record.quote_id}
Origin: ${record.origin}
Destination: ${record.destination}
Weight: ${record.weight_lbs} lbs
Dimensions: ${record.dimensions || 'TBD'}
Hazmat: ${record.hazmat ? 'YES' : 'No'}
Required Pickup: ${record.pickup_date || 'ASAP'}

Please reply with:
1. Your best rate ($)
2. Transit time (days)
3. Availability confirmation

Bid deadline: ${record.bid_deadline}
Include reference ${record.quote_id} in your reply subject line.

AMZ Prep Logistics`;

return carriers.map(carrier => ({
  json: { ...record, carrier_name: carrier, rfq_email_body: rfqBody }
}));

// ── CARRIER RATE PARSER ─────────────────────────────────────
// Extracts real data from carrier email using regex.
// Zero hallucination — only reads what's actually in the email.

const subject = $input.first().json.subject || '';
const from    = $input.first().json.from    || '';
const body    = $input.first().json.text    || '';

// Extract quote ID — match FQ- followed by digits
const quoteIdMatch = subject.match(/FQ-\d+/) || body.match(/FQ-\d+/);
const quoteId = quoteIdMatch ? quoteIdMatch[0] : 'FQ-UNKNOWN';

// Extract carrier name from email domain or signature
let carrierName = 'Unknown Carrier';
if (from.includes('amazon'))    carrierName = 'Amazon Freight';
else if (from.includes('ups'))  carrierName = 'UPS Freight';
else if (from.includes('fedex'))carrierName = 'FedEx Freight';
else if (from.includes('xpo'))  carrierName = 'XPO Logistics';
else if (from.includes('odfl') || from.includes('dominion')) carrierName = 'Old Dominion';
else if (from.includes('estes'))carrierName = 'Estes Express';
else {
  // Try to extract from domain
  const domainMatch = from.match(/@([^.]+)/);
  if (domainMatch) carrierName = domainMatch[1].replace(/-/g, ' ');
}

// Extract rate — find $ followed by numbers
const rateMatch = body.match(/\$([\d,]+(?:\.\d{2})?)/);
const rate = rateMatch ? parseFloat(rateMatch[1].replace(',', '')) : null;

// Extract transit days — number before 'day' or 'business day'
const transitMatch = body.match(/(\d+)\s*(?:business\s*)?days?/i);
const transitDays = transitMatch ? parseInt(transitMatch[1]) : null;

// Check if carrier confirmed availability
const available = /available|confirmed|yes|can do|we can/i.test(body);

// Extract any accessorial charges
const accessorialMatch = body.match(/accessorial[s]?[:\s]+\$?([\d,]+)/i);
const accessorials = accessorialMatch ? parseFloat(accessorialMatch[1].replace(',', '')) : 0;

const totalRate = rate ? rate + accessorials : null;

return [{
  json: {
    quote_id:               quoteId,
    carrier_name:           carrierName,
    rate_usd:               rate,
    transit_days:           transitDays,
    accessorial_charges:    accessorials,
    total_rate:             totalRate,
    availability_confirmed: available,
    notes:                  null,
    parsed_from:            from,
    parsed_at:              new Date().toISOString()
  }
}];

const data = $input.first().json;
const bidDeadline = data.bid_deadline;
const timerExpired = bidDeadline ? new Date() > new Date(bidDeadline) : true;

return [{
  json: {
    ...data,
    should_trigger_rebid: timerExpired,
    quote_id: data.quote_id
  }
}];

const record = $input.first().json;

const mockRates = [
  { carrier: 'Amazon Freight', rate: 920 },
  { carrier: 'UPS Freight',    rate: 1050 },
  { carrier: 'FedEx Freight',  rate: 875 },
  { carrier: 'XPO Logistics',  rate: 990 }
];

const sorted = [...mockRates].sort((a, b) => a.rate - b.rate);
const winner = sorted[0];
const losers = sorted.slice(1);

const rebidMessage = `Re-Bid Request — Final Round

Thank you for your quote on ${record.quote_id}.

We have received a competitive rate of $${winner.rate} for this shipment.

This is your final opportunity to submit your best rate.
Deadline: 30 minutes from receipt of this email.

Please include ${record.quote_id} in your reply subject line.

AMZ Prep Logistics`;

return [{
  json: {
    ...record,
    current_lowest: winner.rate,
    winning_carrier_temp: winner.carrier,
    carriers_to_rebid: losers.map(l => l.carrier),
    rebid_message: rebidMessage,
    rebid_deadline: new Date(Date.now() + 30 * 60 * 1000).toISOString()
  }
}];

const rates = [
  { carrier: 'Amazon Freight', rate: 920 },
  { carrier: 'UPS Freight',    rate: 1050 },
  { carrier: 'FedEx Freight',  rate: 875 },
  { carrier: 'XPO Logistics',  rate: 990 }
];

const winner = rates.reduce((min, r) => r.rate < min.rate ? r : min);
const record = $input.first().json;
const markupPct = record.markup_pct || 0.15;
const sellRate = Math.ceil(winner.rate * (1 + markupPct));
const grossProfit = sellRate - winner.rate;
const grossProfitPct = parseFloat(((grossProfit / sellRate) * 100).toFixed(1));

return [{
  json: {
    ...record,
    winning_carrier:  winner.carrier,
    carrier_rate:     winner.rate,
    markup_pct:       markupPct,
    sell_rate:        sellRate,
    gross_profit_usd: grossProfit,
    gross_profit_pct: grossProfitPct,
    transit_days:     3,
    quote_expiry:     new Date(Date.now() + 4 * 60 * 60 * 1000).toISOString()
  }
}];

