// Parse classification output — handle both JSON and plain text
const raw = $input.first().json.output || '';
const cleaned = raw.replace(/```json/gi, '').replace(/```/g, '').trim();
try {
  return [{ json: JSON.parse(cleaned) }];
} catch(e) {
  // Fallback: detect keywords directly
  const lower = raw.toLowerCase();
  const classification = lower.includes('approved') ? 'APPROVED'
    : lower.includes('rejected') ? 'REJECTED'
    : lower.includes('negotiat') ? 'NEGOTIATING'
    : 'UNCLEAR';
  return [{ json: { classification, confidence: 'MEDIUM', lost_reason: null, competitor_rate: null } }];
}
